// Reduce 16 accumulators to scalars in element [0]
// pix0: ch0→v16[0], ch1→v17[0], ch2→v18[0], ch3→v19[0]
NDS_VEC_VREDSUM_VS(NDS_VEC_V16, NDS_VEC_V0,  NDS_VEC_V31);  //ch0*pix0
